import React from 'react';
import { AppItem } from '../types';
import { MoreHorizontal } from 'lucide-react';
import { motion } from 'framer-motion';

interface AppCardProps {
  item: AppItem;
  onClick: (item: AppItem) => void;
}

const AppCard: React.FC<AppCardProps> = ({ item, onClick }) => {
  // 根据分类选择主色调
  const colors = {
    education: { bg: 'bg-morandi-blue/10', text: 'text-morandi-blue', border: 'border-morandi-blue/20', icon: '#A3B1B7' },
    entertainment: { bg: 'bg-morandi-rose/10', text: 'text-morandi-rose', border: 'border-morandi-rose/20', icon: '#D4A5A5' },
    utilities: { bg: 'bg-morandi-sage/10', text: 'text-morandi-sage', border: 'border-morandi-sage/20', icon: '#A8B7A3' }
  }[item.category];

  return (
    <motion.div 
      initial={{ opacity: 0, y: 20 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true }}
      className="group relative bg-white/60 rounded-[2.5rem] overflow-hidden border border-morandi-border soft-shadow transition-all hover:bg-white hover:-translate-y-1 cursor-pointer"
      onClick={() => onClick(item)}
    >
      <div className="flex p-5 md:p-8 gap-6 md:gap-10 items-center">
        {/* 左侧手绘图标容器 */}
        <div className="w-24 h-24 md:w-32 md:h-32 flex-shrink-0 relative flex items-center justify-center bg-morandi-oatmeal rounded-[2rem] overflow-hidden">
          <div className="absolute inset-0 watercolor-fill opacity-20" style={{ backgroundColor: colors.icon }}></div>
          <ModuleIcon category={item.category} color={colors.icon} />
        </div>

        {/* 右侧信息 */}
        <div className="flex-1 min-w-0">
          <div className="flex justify-between items-start mb-2">
            <h4 className="text-lg md:text-xl font-bold text-morandi-charcoal serif-font truncate">
              {item.title}
            </h4>
            <button className="text-morandi-taupe/50 hover:text-morandi-taupe transition-colors">
              <MoreHorizontal size={20} />
            </button>
          </div>
          <p className="text-morandi-taupe text-sm leading-relaxed mb-4 font-light line-clamp-2">
            {item.description}
          </p>
          <div className="flex gap-2">
            <span className={`px-3 py-0.5 ${colors.bg} ${colors.text} text-[9px] font-bold rounded-lg border ${colors.border} uppercase tracking-widest`}>
              {item.category.toUpperCase()}
            </span>
          </div>
        </div>
      </div>
    </motion.div>
  );
};

// 简单的手绘风格占位图标组件
const ModuleIcon = ({ category, color }: { category: string, color: string }) => {
  if (category === 'education') {
    return (
      <svg fill="none" height="60" viewBox="0 0 100 100" width="60" xmlns="http://www.w3.org/2000/svg">
        <circle className="sketch-path" cx="50" cy="50" fill="none" r="40" stroke={color} strokeWidth="2"></circle>
        <path className="watercolor-fill" d="M35 25 C40 20, 55 25, 60 35 C65 45, 45 60, 40 70 C35 80, 50 85, 65 75" fill={color} stroke={color} strokeWidth="1"></path>
        <path d="M25 50 Q50 55, 75 50" stroke={color} strokeDasharray="3 3" strokeWidth="0.8"></path>
      </svg>
    );
  }
  if (category === 'entertainment') {
    return (
      <svg fill="none" height="60" viewBox="0 0 100 100" width="60" xmlns="http://www.w3.org/2000/svg">
        <rect className="watercolor-fill" fill={color} height="24" rx="4" stroke={color} strokeWidth="1.5" transform="rotate(-5, 35, 35)" width="24" x="25" y="25"></rect>
        <rect className="watercolor-fill" fill={color} height="24" rx="4" stroke={color} strokeWidth="1.5" transform="rotate(8, 65, 35)" width="24" x="55" y="25"></rect>
        <path d="M58 65 H72 M65 58 V72" stroke={color} strokeLinecap="round" strokeWidth="3"></path>
      </svg>
    );
  }
  return (
    <svg fill="none" height="60" viewBox="0 0 100 100" width="60" xmlns="http://www.w3.org/2000/svg">
      <path className="watercolor-fill" d="M50 85 C50 85, 30 75, 25 50 C20 25, 50 15, 50 15 C50 15, 80 25, 75 50 C70 75, 50 85, 50 85Z" fill={color} stroke={color} strokeWidth="1.5"></path>
      <path d="M50 85 L50 20 M50 65 L70 50 M50 50 L30 35" opacity="0.6" stroke="white" strokeLinecap="round" strokeWidth="1.5"></path>
    </svg>
  );
};

export default AppCard;

import React, { useState, useEffect } from 'react';
import { EDUCATION_ITEMS, ENTERTAINMENT_ITEMS, UTILITIES_ITEMS } from './constants';
import { AppItem } from './types';
import AppCard from './components/AppCard';
import Modal from './components/Modal';
import Earth3D from './components/Earth3D';
import FoodChainApp from './components/FoodChainApp';
import CharacterApp from './components/CharacterApp';
import ClockApp from './components/ClockApp';
import WaveApp from './components/WaveApp';
import MathSprintApp from './components/MathSprintApp';
import HistorySortingApp from './components/HistorySortingApp';
import BrainTeaseApp from './components/BrainTeaseApp';
import GobangApp from './components/GobangApp';
import ChineseChessApp from './components/ChineseChessApp';
import ChessApp from './components/ChessApp';
import ProArtApp from './components/ProArtApp';
import VocabularyApp from './components/VocabularyApp';
import IdiomApp from './components/IdiomApp';
import PoetryApp from './components/PoetryApp';
import ThreeCharacterApp from './components/ThreeCharacterApp';
import ThousandCharacterApp from './components/ThousandCharacterApp';
import HeroSpotlight from './components/HeroSpotlight';
import { Search, User, Grid2X2, Compass, Heart, Settings, Plus, BookOpen, Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [selectedItem, setSelectedItem] = useState<AppItem | null>(null);
  const [runningAppId, setRunningAppId] = useState<string | null>(null);
  const [isBooting, setIsBooting] = useState(false);
  const [bootingAppTitle, setBootingAppTitle] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState<string>('ALL');

  const [allModules, setAllModules] = useState<AppItem[]>([]);
  const [user, setUser] = useState<{ email: string } | null>(null);

  const staticModules = [...EDUCATION_ITEMS, ...ENTERTAINMENT_ITEMS, ...UTILITIES_ITEMS];

  useEffect(() => {
    const saved = localStorage.getItem('zst_identity');
    if (saved) {
      setUser(JSON.parse(saved));
    } else {
      const randomId = Math.random().toString(16).slice(2, 6).toUpperCase();
      const identity = { email: `GUEST-${randomId}@zst.local` };
      setUser(identity);
      localStorage.setItem('zst_identity', JSON.stringify(identity));
    }
    setAllModules(staticModules);
  }, []);

  const filteredModules = allModules.filter(item => {
    const matchesSearch = item.title.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesCategory = activeCategory === 'ALL' || item.category.toUpperCase() === activeCategory;
    return matchesSearch && matchesCategory;
  });

  const handleRunApp = (item: AppItem) => {
    setSelectedItem(null); 
    setBootingAppTitle(item.title);
    setIsBooting(true);

    setTimeout(() => {
      setIsBooting(false);
      setRunningAppId(item.id);
    }, 1000);
  };

  const categories = [
    { id: 'ALL', label: '全部' },
    { id: 'EDUCATION', label: '自然科学' },
    { id: 'ENTERTAINMENT', label: '逻辑数学' },
    { id: 'UTILITIES', label: '通用工具' },
  ];

  if (isBooting) {
    return (
      <div className="fixed inset-0 z-[100] bg-morandi-oatmeal flex flex-col items-center justify-center p-6">
        <div className="relative">
          <div className="w-24 h-24 bg-morandi-blue/20 rounded-[2rem] flex items-center justify-center animate-pulse">
            <Loader2 className="w-12 h-12 text-morandi-blue animate-spin" />
          </div>
        </div>
        <h2 className="mt-8 text-center text-xl font-bold text-morandi-charcoal serif-font tracking-wide">
          正在为您准备：{bootingAppTitle}
        </h2>
        <p className="mt-2 text-morandi-taupe text-xs tracking-widest uppercase">Initializing Module...</p>
      </div>
    );
  }

  const renderApp = () => {
    switch (runningAppId) {
      case 'e1': return <Earth3D onClose={() => setRunningAppId(null)} />;
      case 'e2': return <FoodChainApp onClose={() => setRunningAppId(null)} />;
      case 'e3': return <WaveApp onClose={() => setRunningAppId(null)} />;
      case 'e4': return <CharacterApp onClose={() => setRunningAppId(null)} />;
      case 'e5': return <PoetryApp onClose={() => setRunningAppId(null)} />;
      case 'e6': return <HistorySortingApp onClose={() => setRunningAppId(null)} />;
      case 'e7': return <ClockApp onClose={() => setRunningAppId(null)} />;
      case 'e18': return <MathSprintApp onClose={() => setRunningAppId(null)} />;
      case 'e20': return <ThreeCharacterApp onClose={() => setRunningAppId(null)} />;
      case 'e21': return <ThousandCharacterApp onClose={() => setRunningAppId(null)} />;
      case 'ent3': return <BrainTeaseApp onClose={() => setRunningAppId(null)} />;
      case 'ent4': return <GobangApp onClose={() => setRunningAppId(null)} />;
      case 'ent5': return <ChineseChessApp onClose={() => setRunningAppId(null)} />;
      case 'ent6': return <ChessApp onClose={() => setRunningAppId(null)} />;
      case 'u1': return <ProArtApp onClose={() => setRunningAppId(null)} />;
      case 'u2': return <VocabularyApp onClose={() => setRunningAppId(null)} userEmail={user?.email} />;
      case 'u3': return <IdiomApp onClose={() => setRunningAppId(null)} />;
      default: return null;
    }
  };

  if (runningAppId) return renderApp();

  return (
    <div className="min-h-screen bg-morandi-oatmeal text-morandi-charcoal pb-32">
      {/* 顶部导航 */}
      <nav className="sticky top-0 z-50 px-6 py-4 flex items-center justify-between bg-morandi-oatmeal/90 backdrop-blur-lg border-b border-morandi-border/30">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-morandi-taupe/20 rounded-xl flex items-center justify-center border border-morandi-taupe/30">
            <BookOpen className="text-morandi-taupe" size={22} />
          </div>
          <h1 className="text-xl font-bold tracking-tight text-morandi-charcoal serif-font">知识通</h1>
        </div>
        <div className="flex gap-2">
          <button className="w-10 h-10 rounded-full flex items-center justify-center bg-white/50 border border-morandi-border hover:bg-white transition-colors">
            <Search size={18} className="text-morandi-taupe" />
          </button>
          <button className="w-10 h-10 rounded-full flex items-center justify-center bg-white/50 border border-morandi-border hover:bg-white transition-colors">
            <User size={18} className="text-morandi-taupe" />
          </button>
        </div>
      </nav>

      <main className="max-w-4xl mx-auto px-6 pt-4">
        {/* 焦点推荐 */}
        {!searchQuery && activeCategory === 'ALL' && allModules.length > 0 && (
          <HeroSpotlight item={allModules.find(m => m.id === 'ent6') || allModules[0]} onRun={handleRunApp} />
        )}

        {/* 分类标题 */}
        <section className="mb-8">
          <div className="flex items-center justify-between mb-6">
            <h3 className="text-lg font-bold text-morandi-charcoal serif-font">已部署模块</h3>
            <span className="text-xs text-morandi-taupe font-medium cursor-pointer hover:text-morandi-charcoal transition-colors">查看全部</span>
          </div>

          <div className="flex gap-3 overflow-x-auto no-scrollbar -mx-6 px-6 pb-2">
            {categories.map((cat) => (
              <button
                key={cat.id}
                onClick={() => setActiveCategory(cat.id)}
                className={`
                  px-6 py-2.5 rounded-full text-sm font-medium whitespace-nowrap transition-all border
                  ${activeCategory === cat.id 
                    ? 'bg-morandi-charcoal text-white border-morandi-charcoal shadow-md' 
                    : 'bg-white/60 text-morandi-taupe border-morandi-border hover:bg-white'}
                `}
              >
                {cat.label}
              </button>
            ))}
          </div>
        </section>

        {/* 模块网格 */}
        <div className="grid grid-cols-1 gap-6">
          {filteredModules.length > 0 ? (
            filteredModules.map((item) => (
              <AppCard key={item.id} item={item} onClick={setSelectedItem} />
            ))
          ) : (
            <div className="py-20 text-center opacity-40">
              <Loader2 className="w-12 h-12 mb-4 mx-auto animate-spin" />
              <p className="text-sm font-medium uppercase tracking-[0.2em]">无法探测到匹配子节点</p>
            </div>
          )}
        </div>
      </main>

      {/* 底部导航栏 */}
      <footer className="fixed bottom-0 left-0 right-0 z-50 bg-white/80 backdrop-blur-xl border-t border-morandi-border px-4 py-2 safe-bottom">
        <div className="flex justify-around items-center h-16 max-w-lg mx-auto">
          <NavButton icon={<Grid2X2 size={24} />} label="主页" active />
          <NavButton icon={<Compass size={24} />} label="发现" />
          <div className="relative -top-6">
            <button className="w-14 h-14 bg-morandi-charcoal text-white rounded-2xl flex items-center justify-center shadow-lg active:scale-95 transition-transform hover:bg-black">
              <Plus size={28} />
            </button>
          </div>
          <NavButton icon={<Heart size={24} />} label="收藏" />
          <NavButton icon={<Settings size={24} />} label="设置" />
        </div>
      </footer>

      {selectedItem && (
        <Modal 
          item={selectedItem} 
          onClose={() => setSelectedItem(null)} 
          onRun={handleRunApp} 
          user={user} 
        />
      )}
    </div>
  );
};

const NavButton = ({ icon, label, active }: { icon: React.ReactNode, label: string, active?: boolean }) => (
  <button className={`flex flex-col items-center gap-1 transition-colors ${active ? 'text-morandi-charcoal' : 'text-morandi-taupe'}`}>
    {icon}
    <span className="text-[10px] font-bold">{label}</span>
  </button>
);

export default App;

import React, { useEffect, useState } from 'react';
import { X, Heart, Share2, Info, PlayCircle, Loader2, CheckCircle2 } from 'lucide-react';
import { AppItem } from '../types';

interface ModalProps {
  item: AppItem;
  onClose: () => void;
  onRun: (item: AppItem) => void;
  user: { email: string } | null;
}

const Modal: React.FC<ModalProps> = ({ item, onClose, onRun, user }) => {
  const [isVisible, setIsVisible] = useState(false);
  const [copyFeedback, setCopyFeedback] = useState(false);

  useEffect(() => {
    setIsVisible(true);
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = 'auto';
    };
  }, []);

  const handleClose = () => {
    setIsVisible(false);
    setTimeout(onClose, 300);
  };

  return (
    <div className={`fixed inset-0 z-50 flex items-end md:items-center justify-center transition-all duration-300 ${isVisible ? 'bg-morandi-charcoal/20 backdrop-blur-md' : 'bg-transparent pointer-events-none'}`} onClick={handleClose}>
      <div 
        className={`relative w-full md:max-w-2xl h-[85dvh] md:h-auto bg-morandi-oatmeal shadow-2xl rounded-t-[3rem] md:rounded-[3rem] overflow-hidden transform transition-all duration-300 border border-morandi-border ${isVisible ? 'translate-y-0 opacity-100' : 'translate-y-full opacity-0'}`}
        onClick={(e) => e.stopPropagation()}
      >
        <div className="absolute top-4 right-4 z-10">
          <button onClick={handleClose} className="p-2 bg-white/80 hover:bg-white rounded-full transition-colors border border-morandi-border text-morandi-taupe">
            <X size={20} />
          </button>
        </div>

        <div className="h-48 md:h-64 overflow-hidden relative">
          <img src={item.imageUrl} className="w-full h-full object-cover" alt={item.title} />
          <div className="absolute inset-0 bg-gradient-to-t from-morandi-oatmeal via-transparent to-transparent"></div>
          <div className="absolute bottom-6 left-8">
            <h2 className="text-3xl md:text-5xl font-bold text-morandi-charcoal serif-font">{item.title}</h2>
          </div>
        </div>

        <div className="p-8 md:p-12 space-y-8 overflow-y-auto max-h-[calc(85dvh-16rem)] no-scrollbar">
          <section>
            <div className="flex items-center gap-2 mb-4 text-morandi-taupe">
              <Info size={16} />
              <h3 className="text-[10px] font-bold uppercase tracking-widest">模块简介</h3>
            </div>
            <p className="text-lg text-morandi-charcoal leading-relaxed font-light italic">
              {item.description}
            </p>
          </section>

          <div className="flex flex-wrap gap-2">
            {item.tags.map(tag => (
              <span key={tag} className="px-4 py-1.5 bg-white border border-morandi-border text-morandi-taupe text-[10px] font-bold rounded-xl">
                #{tag}
              </span>
            ))}
          </div>

          <div className="flex flex-col sm:flex-row gap-4 pt-4">
            <button 
              onClick={() => onRun(item)}
              className="flex-1 py-4 bg-morandi-charcoal text-white rounded-2xl font-bold flex items-center justify-center gap-3 shadow-lg active:scale-95 transition-all hover:bg-black"
            >
              <PlayCircle size={24} />
              <span>启动程序</span>
            </button>
            <div className="flex gap-4">
              <button className="w-14 h-14 bg-white border border-morandi-border text-morandi-rose rounded-2xl flex items-center justify-center hover:bg-morandi-rose hover:text-white transition-all shadow-sm">
                <Heart size={20} />
              </button>
              <button onClick={() => setCopyFeedback(true)} className="w-14 h-14 bg-white border border-morandi-border text-morandi-blue rounded-2xl flex items-center justify-center hover:bg-morandi-blue hover:text-white transition-all shadow-sm">
                {copyFeedback ? <CheckCircle2 size={20} /> : <Share2 size={20} />}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Modal;

import React, { useState } from 'react';
import { MoreVertical, ChevronRight, BookOpenCheck } from 'lucide-react';
import { motion } from 'framer-motion';

const LibraryView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'SAVED' | 'HISTORY'>('SAVED');

  const savedItems = [
    { id: 1, title: '3D地球 - 大洲探索', status: '2天前打开', progress: 85, color: '#A3B1B7' },
    { id: 2, title: '国际象棋 - 开局进阶', status: '进度: 65%', progress: 65, color: '#D4A5A5' },
  ];

  const historyItems = [
    { id: 3, title: '加减速算挑战 #12', status: '4小时前完成', score: 'A+', color: '#A8B7A3' },
    { id: 4, title: '色彩理论基础', status: '昨日访问', score: null, color: '#B8B0A5' },
  ];

  return (
    <motion.div 
      initial={{ opacity: 0 }} 
      animate={{ opacity: 1 }}
      className="flex-1 flex flex-col px-6 pt-6"
    >
      <header className="flex items-center justify-between mb-8">
        <h2 className="text-2xl font-bold text-morandi-charcoal serif-font">我的图书馆</h2>
        <button className="w-10 h-10 bg-white border border-morandi-border rounded-xl flex items-center justify-center text-morandi-taupe shadow-sm">
          <MoreVertical size={20} />
        </button>
      </header>

      {/* 分段选择器 */}
      <div className="bg-morandi-taupe/10 p-1.5 rounded-[1.5rem] flex mb-8">
        <button 
          onClick={() => setActiveTab('SAVED')}
          className={`flex-1 py-2.5 rounded-2xl text-xs font-bold transition-all ${activeTab === 'SAVED' ? 'bg-white text-morandi-charcoal shadow-sm' : 'text-morandi-taupe'}`}
        >
          已收藏
        </button>
        <button 
          onClick={() => setActiveTab('HISTORY')}
          className={`flex-1 py-2.5 rounded-2xl text-xs font-bold transition-all ${activeTab === 'HISTORY' ? 'bg-white text-morandi-charcoal shadow-sm' : 'text-morandi-taupe'}`}
        >
          历史记录
        </button>
      </div>

      <div className="space-y-6 overflow-y-auto no-scrollbar pb-10">
        <h3 className="text-[10px] font-black text-morandi-taupe uppercase tracking-[0.3em] mb-4">
          {activeTab === 'SAVED' ? '置顶模块' : '最近练习'}
        </h3>

        {(activeTab === 'SAVED' ? savedItems : historyItems).map((item) => (
          <div key={item.id} className="bg-white/60 border border-morandi-border p-5 rounded-[2rem] flex items-center gap-5 soft-shadow hover:bg-white transition-all">
            <div className="w-14 h-14 rounded-2xl flex-shrink-0 flex items-center justify-center relative overflow-hidden" style={{ backgroundColor: `${item.color}20` }}>
              <div className="absolute inset-0 watercolor-fill opacity-20" style={{ backgroundColor: item.color }}></div>
              <BookOpenCheck size={24} style={{ color: item.color }} />
            </div>

            <div className="flex-1 min-w-0">
              <h4 className="font-bold text-morandi-charcoal truncate">{item.title}</h4>
              <p className="text-[10px] text-morandi-taupe font-medium mt-1">{item.status}</p>
              {item.progress !== undefined && (
