type Tab = 'EXPLORE' | 'LIBRARY' | 'PROFILE';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('EXPLORE');
  const [selectedItem, setSelectedItem] = useState<AppItem | null>(null);
  const [runningAppId, setRunningAppId] = useState<string | null>(null);
  const [isBooting, setIsBooting] = useState(false);
  const [bootingAppTitle, setBootingAppTitle] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState<string>('ALL');

  const [allModules, setAllModules] = useState<AppItem[]>([]);
  const [user, setUser] = useState<{ email: string } | null>(null);

  const staticModules = [...EDUCATION_ITEMS, ...ENTERTAINMENT_ITEMS, ...UTILITIES_ITEMS];

  useEffect(() => {
    const saved = localStorage.getItem('zst_identity');
    if (saved) {
      setUser(JSON.parse(saved));
    } else {
      const randomId = Math.random().toString(16).slice(2, 6).toUpperCase();
      const identity = { email: `GUEST-${randomId}@zst.local` };
      setUser(identity);
      localStorage.setItem('zst_identity', JSON.stringify(identity));
    }
    setAllModules(staticModules);
  }, []);

  const filteredModules = allModules.filter(item => {
    const matchesSearch = item.title.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesCategory = activeCategory === 'ALL' || item.category.toUpperCase() === activeCategory;
    return matchesSearch && matchesCategory;
  });

  const handleRunApp = (item: AppItem) => {
    setSelectedItem(null); 
    setBootingAppTitle(item.title);
    setIsBooting(true);

    setTimeout(() => {
      setIsBooting(false);
      setRunningAppId(item.id);
    }, 1000);
  };

  const categories = [
    { id: 'ALL', label: '全部' },
    { id: 'EDUCATION', label: '自然科学' },
    { id: 'ENTERTAINMENT', label: '逻辑数学' },
    { id: 'UTILITIES', label: '通用工具' },
  ];

  if (isBooting) {
    return (
      <div className="fixed inset-0 z-[100] bg-morandi-oatmeal flex flex-col items-center justify-center p-6">
        <div className="relative">
          <div className="w-24 h-24 bg-morandi-blue/20 rounded-[2rem] flex items-center justify-center animate-pulse">
            <Loader2 className="w-12 h-12 text-morandi-blue animate-spin" />
          </div>
        </div>
        <h2 className="mt-8 text-center text-xl font-bold text-morandi-charcoal serif-font tracking-wide">
          正在为您准备：{bootingAppTitle}
        </h2>
        <p className="mt-2 text-morandi-taupe text-xs tracking-widest uppercase">Initializing Module...</p>
      </div>
    );
  }

  const renderApp = () => {
    switch (runningAppId) {
      case 'e1': return <Earth3D onClose={() => setRunningAppId(null)} />;
      case 'e2': return <FoodChainApp onClose={() => setRunningAppId(null)} />;
      case 'e3': return <WaveApp onClose={() => setRunningAppId(null)} />;
      case 'e4': return <CharacterApp onClose={() => setRunningAppId(null)} />;
      case 'e5': return <PoetryApp onClose={() => setRunningAppId(null)} />;
      case 'e6': return <HistorySortingApp onClose={() => setRunningAppId(null)} />;
      case 'e7': return <ClockApp onClose={() => setRunningAppId(null)} />;
      case 'e18': return <MathSprintApp onClose={() => setRunningAppId(null)} />;
      case 'e20': return <ThreeCharacterApp onClose={() => setRunningAppId(null)} />;
      case 'e21': return <ThousandCharacterApp onClose={() => setRunningAppId(null)} />;
      case 'ent3': return <BrainTeaseApp onClose={() => setRunningAppId(null)} />;
      case 'ent4': return <GobangApp onClose={() => setRunningAppId(null)} />;
      case 'ent5': return <ChineseChessApp onClose={() => setRunningAppId(null)} />;
      case 'ent6': return <ChessApp onClose={() => setRunningAppId(null)} />;
      case 'u1': return <ProArtApp onClose={() => setRunningAppId(null)} />;
      case 'u2': return <VocabularyApp onClose={() => setRunningAppId(null)} userEmail={user?.email} />;
      case 'u3': return <IdiomApp onClose={() => setRunningAppId(null)} />;
      default: return null;
    }
  };

  if (runningAppId) return renderApp();

  const renderContent = () => {
    switch (activeTab) {
      case 'LIBRARY':
        return <LibraryView />;
      case 'PROFILE':
        return <SettingsView />;
      case 'EXPLORE':
      default:
        return (
          <div className="flex-1 overflow-y-auto no-scrollbar pb-24">
            <main className="max-w-4xl mx-auto px-6 pt-4">
              {/* 焦点推荐 */}
              {!searchQuery && activeCategory === 'ALL' && allModules.length > 0 && (
                <HeroSpotlight item={allModules.find(m => m.id === 'ent6') || allModules[0]} onRun={handleRunApp} />
              )}

              {/* 分类标题 */}
              <section className="mb-8">
                <div className="flex items-center justify-between mb-6">
                  <h3 className="text-lg font-bold text-morandi-charcoal serif-font">已部署模块</h3>
                  <span className="text-xs text-morandi-taupe font-medium cursor-pointer hover:text-morandi-charcoal transition-colors">查看全部</span>
                </div>

                <div className="flex gap-3 overflow-x-auto no-scrollbar -mx-6 px-6 pb-2">
                  {categories.map((cat) => (
                    <button
                      key={cat.id}
                      onClick={() => setActiveCategory(cat.id)}
                      className={`
                        px-6 py-2.5 rounded-full text-sm font-medium whitespace-nowrap transition-all border
                        ${activeCategory === cat.id 
                          ? 'bg-morandi-charcoal text-white border-morandi-charcoal shadow-md' 
                          : 'bg-white/60 text-morandi-taupe border-morandi-border hover:bg-white'}
                      `}
                    >
                      {cat.label}
                    </button>
                  ))}
                </div>
              </section>

              {/* 模块网格 */}
              <div className="grid grid-cols-1 gap-6">
                {filteredModules.length > 0 ? (
                  filteredModules.map((item) => (
                    <AppCard key={item.id} item={item} onClick={setSelectedItem} />
