        return <ExploreView />;
      case 'LIBRARY':
        return <LibraryView />;
      case 'PROFILE':
        return <SettingsView />;
      case 'HOME':
      default:
        return (
          <div className="flex-1 overflow-y-auto no-scrollbar pb-24">
            <main className="max-w-4xl mx-auto px-6 pt-4">
              {/* 焦点推荐 */}
              {!searchQuery && activeCategory === 'ALL' && allModules.length > 0 && (
                <HeroSpotlight item={allModules.find(m => m.id === 'ent6') || allModules[0]} onRun={handleRunApp} />
              )}

              {/* 分类标题 */}
              <section className="mb-8">
                <div className="flex items-center justify-between mb-6">
                  <h3 className="text-lg font-bold text-morandi-charcoal serif-font">已部署模块</h3>
                  <span className="text-xs text-morandi-taupe font-medium cursor-pointer hover:text-morandi-charcoal transition-colors">查看全部</span>
                </div>

                <div className="flex gap-3 overflow-x-auto no-scrollbar -mx-6 px-6 pb-2">
                  {categories.map((cat) => (
                    <button
                      key={cat.id}
                      onClick={() => setActiveCategory(cat.id)}
                      className={`
                        px-6 py-2.5 rounded-full text-sm font-medium whitespace-nowrap transition-all border
                        ${activeCategory === cat.id 
                          ? 'bg-morandi-charcoal text-white border-morandi-charcoal shadow-md' 
                          : 'bg-white/60 text-morandi-taupe border-morandi-border hover:bg-white'}
                      `}
                    >
                      {cat.label}
                    </button>
                  ))}
                </div>
              </section>

              {/* 模块网格 */}
              <div className="grid grid-cols-1 gap-6">
                {filteredModules.length > 0 ? (
                  filteredModules.map((item) => (
                    <AppCard key={item.id} item={item} onClick={setSelectedItem} />
                  ))
                ) : (
                  <div className="py-20 text-center opacity-40">
                    <Loader2 className="w-12 h-12 mb-4 mx-auto animate-spin" />
                    <p className="text-sm font-medium uppercase tracking-[0.2em]">无法探测到匹配子节点</p>
                  </div>
                )}
              </div>
            </main>
          </div>
        );
    }
  };

  return (
    <div className="h-screen bg-morandi-oatmeal text-morandi-charcoal flex flex-col overflow-hidden">
      {/* 顶部导航 - 适配不同 Tab */}
      <nav className="shrink-0 px-6 py-4 flex items-center justify-between bg-morandi-oatmeal/90 backdrop-blur-lg border-b border-morandi-border/30">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-morandi-taupe/20 rounded-xl flex items-center justify-center border border-morandi-taupe/30">
            {activeTab === 'EXPLORE' ? <Compass className="text-morandi-sage" size={22} /> : <BookOpen className="text-morandi-taupe" size={22} />}
          </div>
          <h1 className="text-xl font-bold tracking-tight text-morandi-charcoal serif-font">
            {activeTab === 'HOME' ? '发现' : activeTab === 'EXPLORE' ? '探索' : activeTab === 'LIBRARY' ? '收藏' : '设置'}
          </h1>
        </div>
        <div className="flex gap-2">
          {activeTab === 'HOME' && (
             <button className="w-10 h-10 rounded-full flex items-center justify-center bg-white/50 border border-morandi-border hover:bg-white transition-colors">
               <Search size={18} className="text-morandi-taupe" />
             </button>
          )}
          {activeTab === 'EXPLORE' && (
             <button className="w-10 h-10 rounded-full flex items-center justify-center bg-morandi-sage/20 border border-morandi-sage/30 text-morandi-sage transition-colors">
               <Sparkles size={18} />
             </button>
          )}
        </div>
      </nav>

      {/* 动态内容区域 */}
      <AnimatePresence mode="wait">
        <div className="flex-1 overflow-hidden flex flex-col">
          {renderContent()}
        </div>
      </AnimatePresence>

      {/* 底部导航栏 */}
      <footer className="shrink-0 bg-white/80 backdrop-blur-xl border-t border-morandi-border px-4 py-2 safe-bottom z-50">
        <div className="flex justify-around items-center h-16 max-w-lg mx-auto">
          <NavButton 
            icon={<Grid2X2 size={24} />} 
            label="首页" 
            active={activeTab === 'HOME'} 
            onClick={() => setActiveTab('HOME')} 
          />
          <NavButton 
            icon={<Compass size={24} />} 
            label="探索" 
            active={activeTab === 'EXPLORE'} 
            onClick={() => setActiveTab('EXPLORE')} 
          />
          <div className="relative -top-6">
            <button className="w-14 h-14 bg-morandi-charcoal text-white rounded-2xl flex items-center justify-center shadow-lg active:scale-95 transition-transform hover:bg-black">
              <Plus size={28} />
            </button>
          </div>
          <NavButton 
            icon={<Heart size={24} />} 
            label="图书馆" 
            active={activeTab === 'LIBRARY'} 
            onClick={() => setActiveTab('LIBRARY')} 
          />
          <NavButton 
            icon={<Settings size={24} />} 
            label="设置" 
            active={activeTab === 'PROFILE'} 
            onClick={() => setActiveTab('PROFILE')} 
          />
        </div>
      </footer>

      {selectedItem && (
        <Modal 
          item={selectedItem} 
          onClose={() => setSelectedItem(null)} 
          onRun={handleRunApp} 
          user={user} 
        />
      )}
    </div>
  );
};

const NavButton = ({ icon, label, active, onClick }: { icon: React.ReactNode, label: string, active?: boolean, onClick: () => void }) => (
  <button 
    onClick={onClick}
    className={`flex flex-col items-center gap-1 transition-colors outline-none ${active ? 'text-morandi-charcoal' : 'text-morandi-taupe'}`}
  >
    {icon}
    <span className="text-[10px] font-bold">{label}</span>
  </button>
);

export default App;

import React, { useState, useEffect } from 'react';
import { EDUCATION_ITEMS, ENTERTAINMENT_ITEMS, UTILITIES_ITEMS } from './constants';
import { AppItem } from './types';
import AppCard from './components/AppCard';
import Modal from './components/Modal';
import Earth3D from './components/Earth3D';
import FoodChainApp from './components/FoodChainApp';
import CharacterApp from './components/CharacterApp';
import ClockApp from './components/ClockApp';
import WaveApp from './components/WaveApp';
import MathSprintApp from './components/MathSprintApp';
import HistorySortingApp from './components/HistorySortingApp';
import BrainTeaseApp from './components/BrainTeaseApp';
import GobangApp from './components/GobangApp';
import ChineseChessApp from './components/ChineseChessApp';
import ChessApp from './components/ChessApp';
import ProArtApp from './components/ProArtApp';
import VocabularyApp from './components/VocabularyApp';
import IdiomApp from './components/IdiomApp';
import PoetryApp from './components/PoetryApp';
import ThreeCharacterApp from './components/ThreeCharacterApp';
import ThousandCharacterApp from './components/ThousandCharacterApp';
import HeroSpotlight from './components/HeroSpotlight';
import LibraryView from './components/LibraryView';
import SettingsView from './components/SettingsView';
import ExploreView from './components/ExploreView';
import { Search, Grid2X2, Compass, Heart, Settings, Plus, BookOpen, Loader2, Sparkles } from 'lucide-react';
import { AnimatePresence } from 'framer-motion';

type Tab = 'HOME' | 'EXPLORE' | 'LIBRARY' | 'PROFILE';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('HOME');
  const [selectedItem, setSelectedItem] = useState<AppItem | null>(null);
  const [runningAppId, setRunningAppId] = useState<string | null>(null);
  const [isBooting, setIsBooting] = useState(false);
  const [bootingAppTitle, setBootingAppTitle] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState<string>('ALL');

  // 收藏与历史状态
  const [savedIds, setSavedIds] = useState<string[]>([]);
  const [historyIds, setHistoryIds] = useState<string[]>([]);
  const [user, setUser] = useState<{ email: string } | null>(null);

  const allModules = [...EDUCATION_ITEMS, ...ENTERTAINMENT_ITEMS, ...UTILITIES_ITEMS];

  useEffect(() => {
    // 加载身份
    const savedIden = localStorage.getItem('zst_identity');
    if (savedIden) setUser(JSON.parse(savedIden));

    // 加载收藏
    const storedSaved = localStorage.getItem('zst_saved_v2');
    if (storedSaved) setSavedIds(JSON.parse(storedSaved));

    // 加载历史
    const storedHistory = localStorage.getItem('zst_history_v2');
    if (storedHistory) setHistoryIds(JSON.parse(storedHistory));
  }, []);

  const handleToggleSave = (id: string) => {
    const newSaved = savedIds.includes(id) 
      ? savedIds.filter(i => i !== id) 
      : [...savedIds, id];
    setSavedIds(newSaved);
    localStorage.setItem('zst_saved_v2', JSON.stringify(newSaved));
  };

  const addToHistory = (id: string) => {
    const filtered = historyIds.filter(i => i !== id);
    const newHistory = [id, ...filtered].slice(0, 15); // 最多保留15条
    setHistoryIds(newHistory);
    localStorage.setItem('zst_history_v2', JSON.stringify(newHistory));
  };

  const handleRunApp = (item: AppItem) => {
    setSelectedItem(null); 
    setBootingAppTitle(item.title);
    setIsBooting(true);
    addToHistory(item.id);

    setTimeout(() => {
      setIsBooting(false);
      setRunningAppId(item.id);
    }, 1000);
  };

  const filteredModules = allModules.filter(item => {
    const matchesSearch = item.title.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesCategory = activeCategory === 'ALL' || item.category.toUpperCase() === activeCategory;
    return matchesSearch && matchesCategory;
  });

  const renderApp = () => {
    switch (runningAppId) {
      case 'e1': return <Earth3D onClose={() => setRunningAppId(null)} />;
      case 'e2': return <FoodChainApp onClose={() => setRunningAppId(null)} />;
      case 'e3': return <WaveApp onClose={() => setRunningAppId(null)} />;
      case 'e4': return <CharacterApp onClose={() => setRunningAppId(null)} />;
      case 'e5': return <PoetryApp onClose={() => setRunningAppId(null)} />;
      case 'e6': return <HistorySortingApp onClose={() => setRunningAppId(null)} />;
      case 'e7': return <ClockApp onClose={() => setRunningAppId(null)} />;
      case 'e18': return <MathSprintApp onClose={() => setRunningAppId(null)} />;
      case 'e20': return <ThreeCharacterApp onClose={() => setRunningAppId(null)} />;
      case 'e21': return <ThousandCharacterApp onClose={() => setRunningAppId(null)} />;
      case 'ent3': return <BrainTeaseApp onClose={() => setRunningAppId(null)} />;
      case 'ent4': return <GobangApp onClose={() => setRunningAppId(null)} />;
      case 'ent5': return <ChineseChessApp onClose={() => setRunningAppId(null)} />;
      case 'ent6': return <ChessApp onClose={() => setRunningAppId(null)} />;
      case 'u1': return <ProArtApp onClose={() => setRunningAppId(null)} />;
      case 'u2': return <VocabularyApp onClose={() => setRunningAppId(null)} userEmail={user?.email} />;
      case 'u3': return <IdiomApp onClose={() => setRunningAppId(null)} />;
      default: return null;
    }
  };

  if (runningAppId) return renderApp();

  const renderContent = () => {
    switch (activeTab) {
      case 'EXPLORE':
        return <ExploreView />;
      case 'LIBRARY':
        return (
          <LibraryView 
            allModules={allModules} 
            savedIds={savedIds} 
            historyIds={historyIds} 
            onOpenItem={setSelectedItem}
          />
        );
      case 'PROFILE':
        return <SettingsView />;
      default:
        return (
          <div className="flex-1 overflow-y-auto no-scrollbar pb-24">
            <main className="max-w-4xl mx-auto px-6 pt-4">
              {!searchQuery && activeCategory === 'ALL' && (
                <HeroSpotlight item={allModules[0]} onRun={handleRunApp} />
              )}
              <section className="mb-8">
                <div className="flex gap-3 overflow-x-auto no-scrollbar -mx-6 px-6 pb-2">
                  {['ALL', 'EDUCATION', 'ENTERTAINMENT', 'UTILITIES'].map((cat) => (
                    <button
                      key={cat}
                      onClick={() => setActiveCategory(cat)}
                      className={`px-6 py-2.5 rounded-full text-sm font-medium whitespace-nowrap transition-all border ${activeCategory === cat ? 'bg-morandi-charcoal text-white border-morandi-charcoal shadow-md' : 'bg-white/60 text-morandi-taupe border-morandi-border'}`}
                    >
                      {cat === 'ALL' ? '全部' : cat === 'EDUCATION' ? '自然科学' : cat === 'ENTERTAINMENT' ? '逻辑数学' : '通用工具'}
                    </button>
                  ))}
                </div>
              </section>
              <div className="grid grid-cols-1 gap-6">
                {filteredModules.map((item) => (
                  <AppCard key={item.id} item={item} onClick={setSelectedItem} />
                ))}
              </div>
            </main>
          </div>
        );
    }
  };

  return (
    <div className="h-screen bg-morandi-oatmeal text-morandi-charcoal flex flex-col overflow-hidden">
      <nav className="shrink-0 px-6 py-4 flex items-center justify-between bg-morandi-oatmeal/90 backdrop-blur-lg border-b border-morandi-border/30">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-morandi-taupe/20 rounded-xl flex items-center justify-center border border-morandi-taupe/30">
            <BookOpen className="text-morandi-taupe" size={22} />
          </div>
          <h1 className="text-xl font-bold tracking-tight text-morandi-charcoal serif-font">
            {activeTab === 'HOME' ? '发现' : activeTab === 'EXPLORE' ? '探索' : activeTab === 'LIBRARY' ? '图书馆' : '个人中心'}
          </h1>
        </div>
      </nav>

      <AnimatePresence mode="wait">
        <div className="flex-1 overflow-hidden flex flex-col">
          {renderContent()}
        </div>
      </AnimatePresence>

      <footer className="shrink-0 bg-white/80 backdrop-blur-xl border-t border-morandi-border px-4 py-2 safe-bottom z-50">
        <div className="flex justify-around items-center h-16 max-w-lg mx-auto">
          <NavButton icon={<Grid2X2 size={24} />} label="发现" active={activeTab === 'HOME'} onClick={() => setActiveTab('HOME')} />
          <NavButton icon={<Compass size={24} />} label="探索" active={activeTab === 'EXPLORE'} onClick={() => setActiveTab('EXPLORE')} />
          <div className="relative -top-6">
            <button className="w-14 h-14 bg-morandi-charcoal text-white rounded-2xl flex items-center justify-center shadow-lg active:scale-95 transition-transform">
              <Plus size={28} />
            </button>
          </div>
          <NavButton icon={<Heart size={24} />} label="收藏" active={activeTab === 'LIBRARY'} onClick={() => setActiveTab('LIBRARY')} />
          <NavButton icon={<Settings size={24} />} label="设置" active={activeTab === 'PROFILE'} onClick={() => setActiveTab('PROFILE')} />
        </div>
      </footer>

      {selectedItem && (
        <Modal 
          item={selectedItem} 
          isSaved={savedIds.includes(selectedItem.id)}
          onToggleSave={handleToggleSave}
          onClose={() => setSelectedItem(null)} 
          onRun={handleRunApp} 
          user={user} 
        />
      )}
    </div>
  );
};

const NavButton = ({ icon, label, active, onClick }: { icon: React.ReactNode, label: string, active?: boolean, onClick: () => void }) => (
  <button onClick={onClick} className={`flex flex-col items-center gap-1 transition-colors ${active ? 'text-morandi-charcoal' : 'text-morandi-taupe'}`}>
    {icon}
    <span className="text-[10px] font-bold">{label}</span>
  </button>
);

export default App;

import React, { useEffect, useState } from 'react';
import { X, Heart, Share2, Info, PlayCircle, CheckCircle2 } from 'lucide-react';
import { AppItem } from '../types';
import { motion, AnimatePresence } from 'framer-motion';

interface ModalProps {
  item: AppItem;
  isSaved: boolean;
  onToggleSave: (id: string) => void;
  onClose: () => void;
  onRun: (item: AppItem) => void;
  user: { email: string } | null;
}

const Modal: React.FC<ModalProps> = ({ item, isSaved, onToggleSave, onClose, onRun, user }) => {
  const [isVisible, setIsVisible] = useState(false);
  const [copyFeedback, setCopyFeedback] = useState(false);

  useEffect(() => {
    setIsVisible(true);
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = 'auto';
    };
  }, []);

  const handleClose = () => {
    setIsVisible(false);
    setTimeout(onClose, 300);
  };

  return (
    <div className={`fixed inset-0 z-50 flex items-end md:items-center justify-center transition-all duration-300 ${isVisible ? 'bg-morandi-charcoal/20 backdrop-blur-md' : 'bg-transparent pointer-events-none'}`} onClick={handleClose}>
      <div 
        className={`relative w-full md:max-w-2xl h-[85dvh] md:h-auto bg-morandi-oatmeal shadow-2xl rounded-t-[3rem] md:rounded-[3rem] overflow-hidden transform transition-all duration-300 border border-morandi-border ${isVisible ? 'translate-y-0 opacity-100' : 'translate-y-full opacity-0'}`}
        onClick={(e) => e.stopPropagation()}
      >
        <div className="absolute top-4 right-4 z-10">
          <button onClick={handleClose} className="p-2 bg-white/80 hover:bg-white rounded-full transition-colors border border-morandi-border text-morandi-taupe">
            <X size={20} />
          </button>
        </div>

        <div className="h-48 md:h-64 overflow-hidden relative">
          <img src={item.imageUrl} className="w-full h-full object-cover" alt={item.title} />
          <div className="absolute inset-0 bg-gradient-to-t from-morandi-oatmeal via-transparent to-transparent"></div>
          <div className="absolute bottom-6 left-8">
            <h2 className="text-3xl md:text-5xl font-bold text-morandi-charcoal serif-font">{item.title}</h2>
          </div>
        </div>

        <div className="p-8 md:p-12 space-y-8 overflow-y-auto max-h-[calc(85dvh-16rem)] no-scrollbar">
          <section>
            <div className="flex items-center gap-2 mb-4 text-morandi-taupe">
              <Info size={16} />
              <h3 className="text-[10px] font-bold uppercase tracking-widest">模块简介</h3>
            </div>
            <p className="text-lg text-morandi-charcoal leading-relaxed font-light italic">
              {item.description}
            </p>
          </section>

          <div className="flex flex-wrap gap-2">
            {item.tags.map(tag => (
              <span key={tag} className="px-4 py-1.5 bg-white border border-morandi-border text-morandi-taupe text-[10px] font-bold rounded-xl">
                #{tag}
              </span>
            ))}
          </div>

          <div className="flex flex-col sm:flex-row gap-4 pt-4 pb-8">
            <button 
              onClick={() => onRun(item)}
              className="flex-1 py-4 bg-morandi-charcoal text-white rounded-2xl font-bold flex items-center justify-center gap-3 shadow-lg active:scale-95 transition-all hover:bg-black"
            >
              <PlayCircle size={24} />
              <span>启动程序</span>
            </button>
            <div className="flex gap-4">
              <motion.button 
                whileTap={{ scale: 1.2 }}
                onClick={() => onToggleSave(item.id)}
                className={`w-14 h-14 border rounded-2xl flex items-center justify-center transition-all shadow-sm ${isSaved ? 'bg-morandi-rose border-morandi-rose text-white' : 'bg-white border-morandi-border text-morandi-rose hover:bg-morandi-rose/5'}`}
              >
                <Heart size={20} fill={isSaved ? "currentColor" : "none"} />
              </motion.button>
              <button onClick={() => { setCopyFeedback(true); setTimeout(()=>setCopyFeedback(false), 2000); }} className="w-14 h-14 bg-white border border-morandi-border text-morandi-blue rounded-2xl flex items-center justify-center hover:bg-morandi-blue hover:text-white transition-all shadow-sm">
                {copyFeedback ? <CheckCircle2 size={20} /> : <Share2 size={20} />}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Modal;

import React, { useState, useMemo } from 'react';
import { MoreVertical, ChevronRight, BookOpenCheck, Bookmark, History, Sparkles, ArrowRight } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { AppItem } from '../types';

interface LibraryViewProps {
  allModules: AppItem[];
  savedIds: string[];
  historyIds: string[];
  onOpenItem: (item: AppItem) => void;
}

const LibraryView: React.FC<LibraryViewProps> = ({ allModules, savedIds, historyIds, onOpenItem }) => {
  const [activeTab, setActiveTab] = useState<'SAVED' | 'HISTORY'>('SAVED');

  const savedItems = useMemo(() => 
    allModules.filter(m => savedIds.includes(m.id)), 
  [allModules, savedIds]);

  const historyItems = useMemo(() => 
    historyIds.map(id => allModules.find(m => m.id === id)).filter(Boolean) as AppItem[],
  [allModules, historyIds]);

  const currentList = activeTab === 'SAVED' ? savedItems : historyItems;

  const categoryColors: Record<string, string> = {
    education: '#A3B1B7',
    entertainment: '#D4A5A5',
    utilities: '#A8B7A3'
  };

  return (
    <motion.div 
      initial={{ opacity: 0, x: 20 }} 
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0, x: -20 }}
      className="flex-1 flex flex-col px-6 pt-6 overflow-hidden"
    >
      <header className="flex items-center justify-between mb-8 shrink-0">
        <h2 className="text-2xl font-bold text-morandi-charcoal serif-font">我的图书馆</h2>
        <div className="p-2 bg-white/50 border border-morandi-border rounded-xl">
           <Sparkles size={18} className="text-morandi-taupe" />
        </div>
      </header>

      {/* 分段选择器 */}
      <div className="bg-morandi-taupe/10 p-1.5 rounded-[1.5rem] flex mb-8 shrink-0">
        <button 
          onClick={() => setActiveTab('SAVED')}
          className={`flex-1 py-2.5 rounded-2xl text-xs font-bold transition-all flex items-center justify-center gap-2 ${activeTab === 'SAVED' ? 'bg-white text-morandi-charcoal shadow-sm' : 'text-morandi-taupe'}`}
        >
          <Bookmark size={14} /> 收藏集 ({savedItems.length})
        </button>
        <button 
          onClick={() => setActiveTab('HISTORY')}
          className={`flex-1 py-2.5 rounded-2xl text-xs font-bold transition-all flex items-center justify-center gap-2 ${activeTab === 'HISTORY' ? 'bg-white text-morandi-charcoal shadow-sm' : 'text-morandi-taupe'}`}
        >
          <History size={14} /> 历史记录
        </button>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar pb-24">
        <AnimatePresence mode="wait">
          {currentList.length > 0 ? (
            <motion.div 
              key={activeTab}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className="space-y-4"
            >
              {currentList.map((item, idx) => (
                <motion.div 
                  key={`${item.id}-${idx}`}
                  whileHover={{ scale: 1.02 }}
                  whileTap={{ scale: 0.98 }}
                  onClick={() => onOpenItem(item)}
                  className="bg-white/60 border border-morandi-border p-4 rounded-[2rem] flex items-center gap-4 soft-shadow cursor-pointer transition-all hover:bg-white"
                >
                  <div className="w-16 h-16 rounded-2xl flex-shrink-0 flex items-center justify-center relative overflow-hidden" style={{ backgroundColor: `${categoryColors[item.category]}20` }}>
                    <div className="absolute inset-0 watercolor-fill opacity-20" style={{ backgroundColor: categoryColors[item.category] }}></div>
                    <img src={item.imageUrl} className="w-full h-full object-cover opacity-60" alt="" />
                    <BookOpenCheck size={20} className="absolute text-white drop-shadow-md" />
                  </div>

                  <div className="flex-1 min-w-0">
                    <h4 className="font-bold text-morandi-charcoal truncate text-sm">{item.title}</h4>
                    <p className="text-[10px] text-morandi-taupe font-medium mt-1 uppercase tracking-wider">{item.category}</p>
                  </div>

                  <ChevronRight size={16} className="text-morandi-border" />
