              ))}
            </motion.div>
          ) : (
            <motion.div 
              key="empty"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              className="flex flex-col items-center justify-center py-20 text-center"
            >
              <div className="w-32 h-32 bg-morandi-taupe/10 rounded-full flex items-center justify-center mb-6 relative">
                 <div className="absolute inset-0 watercolor-fill opacity-10 bg-morandi-charcoal"></div>
                 <BookOpen size={48} className="text-morandi-taupe/40" />
              </div>
              <h3 className="text-lg font-bold text-morandi-charcoal serif-font mb-2">
                {activeTab === 'SAVED' ? '还没有收藏任何模块' : '暂无历史记录'}
